import React, { useEffect, useState } from 'react';
import api from '../api';
import { Doctor } from '../types'; // Siguroha nga husto ang path

const DoctorList: React.FC = () => {
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editData, setEditData] = useState<Doctor | null>(null);

  useEffect(() => { fetchDoctors(); }, []);

  const fetchDoctors = async () => {
    const res = await api.get('doctors/');
    setDoctors(res.data);
  };

  const startEditing = (doctor: Doctor) => {
    setEditingId(doctor.doctor_id);
    setEditData({ ...doctor }); // I-copy tanan aron dili ma-null ang uban
  };

  const handleUpdate = async (id: number) => {
    if (!editData) return;
    try {
      await api.put(`doctors/${id}/`, editData);
      setEditingId(null);
      fetchDoctors();
    } catch (err: any) {
      console.error("Error:", err.response?.data); // I-check diri kung unsay kulang
    }
  };

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold mb-4">Doctors</h2>
      {doctors.map(d => (
        <div key={d.doctor_id} className="border p-2 mb-2 flex justify-between">
          {editingId === d.doctor_id ? (
            <input value={editData?.specialization} onChange={e => setEditData({...editData!, specialization: e.target.value})} />
          ) : (
            <span>Dr. {d.last_name} ({d.specialization})</span>
          )}
          <button onClick={() => editingId === d.doctor_id ? handleUpdate(d.doctor_id) : startEditing(d)}>
            {editingId === d.doctor_id ? 'Save' : 'Edit'}
          </button>
        </div>
      ))}
    </div>
  );
};
export default DoctorList;
